@page "/directory"
@using sv_1979345610f14796b2895db36d81d388.Services
@inject IEmployeeService EmployeeService
@rendermode InteractiveServer

<PageTitle>Employee Directory</PageTitle>

<div class="directory-page">
    @* Top Summary Bar *@
    <div class="kpi-bar">
        <div class="kpi-card">
            <div class="kpi-value">@totalEmployees</div>
            <div class="kpi-label">Total Employees</div>
        </div>
        <div class="kpi-card">
            <div class="kpi-value">@totalDepartments</div>
            <div class="kpi-label">Departments</div>
        </div>
        <div class="kpi-card">
            <div class="kpi-value">@averageTenure.ToString("F1")</div>
            <div class="kpi-label">Avg Tenure (years)</div>
        </div>
        <div class="kpi-card">
            <div class="kpi-value">@totalLocations</div>
            <div class="kpi-label">Locations</div>
        </div>
    </div>

    @* Main Content *@
    <div class="directory-content">
        @* Left Sidebar *@
        <aside class="sidebar">
            <div class="filters">
                <input type="text" class="filter-input" placeholder="Search by name..."
                       @bind="searchQuery" @bind:event="oninput" />

                <select class="filter-select" @bind="selectedDepartment">
                    <option value="">All Departments</option>
                    @foreach (var dept in departments)
                    {
                        <option value="@dept">@dept</option>
                    }
                </select>

                <select class="filter-select" @bind="selectedLocation">
                    <option value="">All Locations</option>
                    @foreach (var loc in locations)
                    {
                        <option value="@loc">@loc</option>
                    }
                </select>

                <div class="filter-buttons">
                    <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
                    <button class="btn btn-secondary" @onclick="ClearFilters">Clear Filters</button>
                </div>
            </div>

            <div class="employee-list">
                @foreach (var emp in filteredEmployees)
                {
                    <div class="employee-card @(selectedEmployee?.Id == emp.Id ? "selected" : "")"
                         @onclick="() => SelectEmployee(emp)">
                        <div class="avatar-circle">@GetInitials(emp.Name)</div>
                        <div class="card-info">
                            <div class="card-name">@emp.Name</div>
                            <div class="card-title">@emp.Title</div>
                            <span class="dept-badge" style="background-color: @GetDepartmentColor(emp.Department)">@emp.Department</span>
                        </div>
                    </div>
                }
            </div>
        </aside>

        @* Main Detail Area *@
        <main class="detail-panel">
            @if (selectedEmployee is null)
            {
                <div class="placeholder-message">
                    <p>Select an employee to view details</p>
                </div>
            }
            else
            {
                <div class="detail-header">
                    <div class="avatar-large">@GetInitials(selectedEmployee.Name)</div>
                    <div class="detail-header-info">
                        <h2>@selectedEmployee.Name</h2>
                        <p class="detail-title">@selectedEmployee.Title</p>
                        <span class="dept-badge" style="background-color: @GetDepartmentColor(selectedEmployee.Department)">@selectedEmployee.Department</span>
                        <p class="detail-location">📍 @selectedEmployee.Location</p>
                    </div>
                </div>

                <div class="info-grid">
                    <div class="info-item">
                        <span class="info-label">Email</span>
                        <span class="info-value">@selectedEmployee.Email</span>
                    </div>
                    <div class="info-item">
                        <span class="info-label">Hire Date</span>
                        <span class="info-value">@selectedEmployee.HireDate.ToString("MMMM dd, yyyy")</span>
                    </div>
                    <div class="info-item">
                        <span class="info-label">Tenure</span>
                        <span class="info-value">@GetTenureYears(selectedEmployee.HireDate) years</span>
                    </div>
                    <div class="info-item">
                        <span class="info-label">Manager</span>
                        <span class="info-value">@selectedEmployee.ManagerName</span>
                    </div>
                </div>

                <div class="direct-reports-section">
                    <h3>Direct Reports</h3>
                    @if (isLoadingReports)
                    {
                        <p>Loading...</p>
                    }
                    else if (directReports.Count == 0)
                    {
                        <p class="no-reports">No direct reports</p>
                    }
                    else
                    {
                        <div class="direct-reports-list">
                            @foreach (var report in directReports)
                            {
                                <div class="employee-card" @onclick="() => SelectEmployee(report)">
                                    <div class="avatar-circle">@GetInitials(report.Name)</div>
                                    <div class="card-info">
                                        <div class="card-name">@report.Name</div>
                                        <div class="card-title">@report.Title</div>
                                        <span class="dept-badge" style="background-color: @GetDepartmentColor(report.Department)">@report.Department</span>
                                    </div>
                                </div>
                            }
                        </div>
                    }
                </div>
            }
        </main>
    </div>

    @* Footer *@
    <footer class="directory-footer">
        <span>Showing @filteredEmployees.Count of @allEmployees.Count employees</span>
    </footer>
</div>

@code {
    private string searchQuery = string.Empty;
    private string selectedDepartment = string.Empty;
    private string selectedLocation = string.Empty;

    private List<string> departments = new();
    private List<string> locations = new();
    private List<Employee> allEmployees = new();
    private List<Employee> filteredEmployees = new();
    private List<Employee> directReports = new();
    private List<DepartmentSummary> departmentSummaries = new();

    private Employee? selectedEmployee;
    private bool isLoadingReports;

    private int totalEmployees;
    private int totalDepartments;
    private decimal averageTenure;
    private int totalLocations;

    protected override async Task OnInitializedAsync()
    {
        var departmentsTask = EmployeeService.GetDepartmentsAsync();
        var locationsTask = EmployeeService.GetLocationsAsync();
        var summariesTask = EmployeeService.GetDepartmentSummariesAsync();
        var employeesTask = EmployeeService.SearchAsync(null, null, null);

        await Task.WhenAll(departmentsTask, locationsTask, summariesTask, employeesTask);

        departments = departmentsTask.Result;
        locations = locationsTask.Result;
        departmentSummaries = summariesTask.Result;
        allEmployees = employeesTask.Result;
        filteredEmployees = allEmployees;

        totalEmployees = departmentSummaries.Sum(d => d.HeadCount);
        totalDepartments = departmentSummaries.Count;
        averageTenure = departmentSummaries.Count > 0
            ? departmentSummaries.Average(d => d.AverageTenureYears)
            : 0;
        totalLocations = locations.Count;
    }

    private async Task ApplyFilters()
    {
        var query = string.IsNullOrWhiteSpace(searchQuery) ? null : searchQuery;
        var dept = string.IsNullOrWhiteSpace(selectedDepartment) ? null : selectedDepartment;
        var loc = string.IsNullOrWhiteSpace(selectedLocation) ? null : selectedLocation;

        filteredEmployees = await EmployeeService.SearchAsync(query, dept, loc);
    }

    private async Task ClearFilters()
    {
        searchQuery = string.Empty;
        selectedDepartment = string.Empty;
        selectedLocation = string.Empty;
        filteredEmployees = allEmployees;
    }

    private async Task SelectEmployee(Employee employee)
    {
        selectedEmployee = employee;
        isLoadingReports = true;
        directReports = new();

        directReports = await EmployeeService.GetDirectReportsAsync(employee.Id);
        isLoadingReports = false;
    }

    private static string GetInitials(string name)
    {
        var parts = name.Split(' ', StringSplitOptions.RemoveEmptyEntries);
        if (parts.Length >= 2)
            return $"{parts[0][0]}{parts[^1][0]}".ToUpper();
        return parts.Length == 1 ? parts[0][0].ToString().ToUpper() : "?";
    }

    private static string GetTenureYears(DateTime hireDate)
    {
        var tenure = (DateTime.Today - hireDate.Date).TotalDays / 365.25;
        return tenure.ToString("F1");
    }

    private static string GetDepartmentColor(string department)
    {
        var hash = department.GetHashCode();
        var hue = Math.Abs(hash % 360);
        return $"hsl({hue}, 55%, 45%)";
    }
}

