                        <div class="avatar-circle">@GetInitials(emp.Name)</div>
                        <div class="card-info">
                            <div class="card-name">@emp.Name</div>
                            <div class="card-title">@emp.Title</div>
                            <span class="dept-badge" style="background-color: @GetDepartmentColor(emp.Department)">@emp.Department</span>
                        </div>
                    </div>
                }
            </div>
