                                        <div class="card-name">@report.Name</div>
                                        <div class="card-title">@report.Title</div>
                                        <span class="dept-badge" style="background-color: @GetDepartmentColor(report.Department)">@report.Department</span>
                                    </div>
                                </div>
                            }
                        </div>
                    }
                </div>
            }
        </main>
    </div>

    @* Footer *@
    <footer class="directory-footer">
        <span>Showing @filteredEmployees.Count of @allEmployees.Count employees</span>
    </footer>
</div>

