.directory-page {
    display: flex;
    flex-direction: column;
    height: 100vh;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    background: #f4f6f9;
}

/* KPI Bar */
.kpi-bar {
    display: flex;
    gap: 1rem;
    padding: 1.25rem 1.5rem;
    background: #fff;
    border-bottom: 1px solid #e2e8f0;
}

.kpi-card {
    flex: 1;
    text-align: center;
    padding: 1rem;
    background: #f8fafc;
    border-radius: 8px;
    border: 1px solid #e2e8f0;
}

.kpi-value {
    font-size: 1.75rem;
    font-weight: 700;
    color: #1e293b;
}

.kpi-label {
    font-size: 0.8rem;
    color: #64748b;
    margin-top: 0.25rem;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

/* Content Layout */
.directory-content {
    display: flex;
    flex: 1;
    overflow: hidden;
}

/* Sidebar */
.sidebar {
    width: 25%;
    min-width: 280px;
    background: #fff;
    border-right: 1px solid #e2e8f0;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.filters {
    padding: 1rem;
    border-bottom: 1px solid #e2e8f0;
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
}

.filter-input,
.filter-select {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #d1d5db;
    border-radius: 6px;
    font-size: 0.875rem;
    box-sizing: border-box;
}

.filter-input:focus,
.filter-select:focus {
    outline: none;
    border-color: #3b82f6;
    box-shadow: 0 0 0 2px rgba(59, 130, 246, 0.15);
}

.filter-buttons {
    display: flex;
    gap: 0.5rem;
}

.btn {
    flex: 1;
    padding: 0.5rem 0.75rem;
    border: none;
    border-radius: 6px;
    font-size: 0.8rem;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-primary {
    background: #3b82f6;
    color: #fff;
}

.btn-primary:hover {
    background: #2563eb;
}

.btn-secondary {
    background: #e2e8f0;
    color: #475569;
}

.btn-secondary:hover {
    background: #cbd5e1;
}

/* Employee List */
.employee-list {
    flex: 1;
    overflow-y: auto;
    padding: 0.5rem;
}

.employee-card {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem;
    border-radius: 8px;
    cursor: pointer;
    transition: background 0.15s;
}

.employee-card:hover {
    background: #f1f5f9;
}

.employee-card.selected {
    background: #eff6ff;
    border: 1px solid #bfdbfe;
}

.avatar-circle {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    background: #6366f1;
    color: #fff;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.8rem;
    font-weight: 600;
    flex-shrink: 0;
}

.card-info {
    min-width: 0;
}

.card-name {
    font-weight: 600;
    font-size: 0.875rem;
    color: #1e293b;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.card-title {
    font-size: 0.75rem;
    color: #64748b;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.dept-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 12px;
    font-size: 0.7rem;
    font-weight: 500;
    color: #fff;
    margin-top: 0.25rem;
}

/* Detail Panel */
.detail-panel {
    flex: 1;
    overflow-y: auto;
    padding: 2rem;
}

.placeholder-message {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #94a3b8;
    font-size: 1.1rem;
}

.detail-header {
    display: flex;
    align-items: center;
    gap: 1.5rem;
    margin-bottom: 2rem;
}

.avatar-large {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    background: #6366f1;
    color: #fff;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.5rem;
    font-weight: 700;
    flex-shrink: 0;
}

.detail-header-info h2 {
    margin: 0 0 0.25rem;
    color: #1e293b;
}

.detail-title {
    margin: 0 0 0.5rem;
    color: #475569;
}

.detail-location {
    margin: 0.5rem 0 0;
    color: #64748b;
    font-size: 0.9rem;
}

/* Info Grid */
.info-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1.25rem;
    background: #fff;
    padding: 1.5rem;
    border-radius: 10px;
    border: 1px solid #e2e8f0;
    margin-bottom: 2rem;
}

.info-item {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

.info-label {
    font-size: 0.75rem;
    color: #94a3b8;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.info-value {
    font-size: 0.95rem;
    color: #1e293b;
    font-weight: 500;
}

/* Direct Reports */
.direct-reports-section h3 {
    margin-bottom: 1rem;
    color: #334155;
}

.direct-reports-list {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
    gap: 0.75rem;
}

.direct-reports-list .employee-card {
    background: #fff;
    border: 1px solid #e2e8f0;
    border-radius: 8px;
}

.direct-reports-list .employee-card:hover {
    border-color: #93c5fd;
    background: #eff6ff;
}

.no-reports {
    color: #94a3b8;
    font-style: italic;
}

/* Footer */
.directory-footer {
    padding: 0.75rem 1.5rem;
    background: #fff;
    border-top: 1px solid #e2e8f0;
    font-size: 0.85rem;
    color: #64748b;
