+    color: #1e293b;
+}
+
+.detail-title {
+    margin: 0 0 0.5rem;
+    color: #475569;
+}
+
+.detail-location {
+    margin: 0.5rem 0 0;
+    color: #64748b;
+    font-size: 0.9rem;
+}
+
+/* Info Grid */
+.info-grid {
+    display: grid;
+    grid-template-columns: 1fr 1fr;
+    gap: 1.25rem;
+    background: #fff;
+    padding: 1.5rem;
+    border-radius: 10px;
+    border: 1px solid #e2e8f0;
+    margin-bottom: 2rem;
+}
+
+.info-item {
+    display: flex;
+    flex-direction: column;
+    gap: 0.25rem;
+}
+
+.info-label {
+    font-size: 0.75rem;
+    color: #94a3b8;
+    text-transform: uppercase;
+    letter-spacing: 0.5px;
+}
+
+.info-value {
+    font-size: 0.95rem;
+    color: #1e293b;
+    font-weight: 500;
+}
+
+/* Direct Reports */
+.direct-reports-section h3 {
+    margin-bottom: 1rem;
+    color: #334155;
+}
+
+.direct-reports-list {
+    display: grid;
+    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
+    gap: 0.75rem;
+}
+
+.direct-reports-list .employee-card {
+    background: #fff;
+    border: 1px solid #e2e8f0;
+    border-radius: 8px;
+}
+
+.direct-reports-list .employee-card:hover {
+    border-color: #93c5fd;
+    background: #eff6ff;
+}
+
+.no-reports {
+    color: #94a3b8;
+    font-style: italic;
+}
+
+/* Footer */
+.directory-footer {
+    padding: 0.75rem 1.5rem;
+    background: #fff;
+    border-top: 1px solid #e2e8f0;
+    font-size: 0.85rem;
+    color: #64748b;
+}
+

